#!/usr/bin/env node
/**
 * HoloShell Operate Room — compile to standalone HTML
 * @generated by HoloScript Native2DCompiler
 *
 * Usage: node packages/holoshell/compile.mjs  (from Hololand root)
 * Output: packages/holoshell/dist/operate-room.html
 *
 * Source: packages/holoshell/scenes/operate-room.holo
 * Runtime data tier: serve.mjs (localhost:8747)
 * Phase D graduation: publish machine state to Studio operate-room surface (D.081)
 */

import { Native2DCompiler } from '@holoscript/core/compiler';
import { writeFileSync, mkdirSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DIST_DIR = join(__dirname, 'dist');

// ── AST helpers ───────────────────────────────────────────────────────────────

function t(name, config) {
  return { type: 'ObjectTrait', name, config };
}

function obj(name, traits, children = []) {
  return { type: 'Object', name, properties: [], traits, children };
}

function panel(name, id, children) {
  return obj(name, [
    t('theme', {
      tag: 'section',
      id,
      backgroundColor: '#0d1117',
      borderRadius: 12,
      border: '1px solid #30363d',
      padding: 20,
    }),
    t('layout', { flex: 'column', gap: 12 }),
  ], children);
}

function panelTitle(name, content) {
  return obj(name, [t('text', { variant: 'h3', content })]);
}

function fetchList(name, endpoint, into, rowChildren) {
  return obj(name, [
    t('theme', { tag: 'div', id: `${name}-container` }),
    t('fetch', { endpoint, into, method: 'GET' }),
  ], [
    obj(`${name}-row`, [
      t('theme', {
        tag: 'div',
        style: 'padding:10px 14px;border-radius:8px;background:#161b22;margin-bottom:8px;display:flex;justify-content:space-between;align-items:center;gap:12px;font-size:13px;font-family:system-ui,sans-serif',
      }),
    ], rowChildren),
  ]);
}

// ── Panels ────────────────────────────────────────────────────────────────────

const stalePanel = panel('staleSection', 'stale-processes', [
  panelTitle('staleTitle', 'Stale Processes'),
  obj('staleCount', [
    t('theme', { tag: 'p', style: 'font-size:12px;color:#6e7681;margin:0 0 8px' }),
    t('text', { content: '' }),
  ]),
  fetchList('staleList', '/api/stale-processes', 'staleProcesses', [
    obj('stalePid', [t('text', { content: 'PID {{pid}} — {{reason}}', variant: 'body' })]),
    obj('staleAge', [t('text', { content: '{{ageSec}}s', variant: 'caption' })]),
  ]),
]);

const consentsPanel = panel('consentsSection', 'pending-consents', [
  panelTitle('consentsTitle', 'Pending Consents'),
  fetchList('consentsList', '/api/pending-consents', 'pendingConsents', [
    obj('consentInfo', [
      t('text', { content: '{{operation}} ({{targetCount}} targets)', variant: 'body' }),
    ]),
    obj('consentApprove', [
      t('button', { content: 'Approve', variant: 'primary', onClick: "approveConsent('{{id}}')" }),
    ]),
  ]),
]);

const historyPanel = panel('historySection', 'execution-history', [
  panelTitle('historyTitle', 'Execution History'),
  fetchList('historyList', '/api/execution-history', 'executionHistory', [
    obj('historyOp', [
      t('text', { content: '{{operation}} — killed:{{summary.killed}} err:{{summary.errors}}', variant: 'body' }),
    ]),
    obj('historyTime', [t('text', { content: '{{executedAtShort}}', variant: 'caption' })]),
  ]),
]);

const pressurePanel = panel('pressureSection', 'substrate-pressure', [
  panelTitle('pressureTitle', 'Substrate Pressure'),
  fetchList('pressureList', '/api/substrate-pressure', 'substrateMetrics', [
    obj('metricName', [t('text', { content: '{{metric}}', variant: 'body' })]),
    obj('metricValue', [t('text', { content: '{{value}}', variant: 'caption' })]),
  ]),
]);

// Worktree Health — the #1 recurring local-agent friction (stale index.lock blocks
// every commit; orphan worktrees). Surfaced so any agent sees + clears it locally.
const worktreePanel = panel('worktreeSection', 'worktree-health', [
  panelTitle('worktreeTitle', 'Worktree Health'),
  fetchList('worktreeList', '/api/worktree-health', 'worktreeHealth', [
    obj('worktreeRepo', [t('text', { content: '{{label}}', variant: 'body' })]),
    obj('worktreeStatus', [t('text', { content: '{{status}}', variant: 'caption' })]),
  ]),
]);

// Brittney — System Management chat. Front-and-center (full-width, above the data grid).
// Routes to the HoloShell Brittney operator loop via POST /api/brittney/chat and renders
// her reply + permission-enveloped action proposals. The interactive DOM (messages/input/
// send) is built by the injected runtime helper; Native2D renders the panel shell + mount.
const brittneyPanel = panel('brittneySection', 'brittney-chat', [
  panelTitle('brittneyTitle', '🛰 Brittney — System Management'),
  obj('brittneyMount', [t('theme', { tag: 'div', id: 'brittney-chat-mount' })]),
]);

// Daimon — the emergent companion (D.053). Sits beside Brittney on the management surface:
// reads the live ConversationDaemon substrate (/api/daimon/status). NOT granted — it manifests
// once enough soul-context accumulates, then its turns feed the Brittney rehydration channel.
const daimonPanel = panel('daimonSection', 'daimon-presence', [
  panelTitle('daimonTitle', '🜂 Daimon — Emergent Companion'),
  fetchList('daimonList', '/api/daimon/status', 'daimonStatus', [
    obj('daimonName', [t('text', { content: '{{label}}', variant: 'body' })]),
    obj('daimonState', [t('text', { content: '{{status}}', variant: 'caption' })]),
  ]),
]);

// ── Composition ───────────────────────────────────────────────────────────────

const composition = {
  type: 'Composition',
  name: 'OperateRoom',
  objects: [
    obj('root', [
      t('theme', {
        tag: 'div',
        id: 'operate-root',
        style: 'min-height:100vh;padding:20px;box-sizing:border-box;max-width:1400px;margin:0 auto',
      }),
      t('layout', { flex: 'column', gap: 20 }),
    ], [
      obj('header', [
        t('theme', {
          tag: 'header',
          style: 'display:flex;justify-content:space-between;align-items:center;padding-bottom:16px;border-bottom:1px solid #30363d',
        }),
      ], [
        obj('title', [t('text', { variant: 'h1', content: 'HoloShell Operate Room' })]),
        obj('refreshBtn', [t('button', { content: 'Refresh', variant: 'outline', onClick: 'location.reload()' })]),
      ]),
      brittneyPanel,
      obj('grid', [
        t('theme', { tag: 'main', style: 'display:grid;grid-template-columns:1fr 1fr;gap:16px' }),
      ], [daimonPanel, stalePanel, consentsPanel, historyPanel, pressurePanel, worktreePanel]),
    ]),
  ],
  templates: [],
  spatialGroups: [],
  lights: [],
  imports: [],
  timelines: [],
  audio: [],
  zones: [],
  transitions: [],
  conditionals: [],
  iterators: [],
  npcs: [],
  quests: [],
  abilities: [],
  dialogues: [],
  stateMachines: [],
  achievements: [],
  talentTrees: [],
  shapes: [],
  state: { type: 'State', properties: [] },
  environment: {
    properties: [
      { key: 'theme', value: 'dark' },
      { key: 'backgroundColor', value: '#0d1117' },
    ],
  },
};

// ── Compile ───────────────────────────────────────────────────────────────────

let html = new Native2DCompiler().compile(composition, '');

// Inject approveConsent + auto-refresh helpers before </body>
const runtimeScript = `  <script>
    /* HoloShell operate-room runtime helpers */
    function approveConsent(preflightId) {
      if (!confirm('Approve and execute consent for preflight:\\n' + preflightId + '\\n\\nThis will kill all stale processes in the receipt.')) return;
      fetch('/api/consent/approve', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ preflightId: preflightId })
      })
      .then(function(r) { return r.json(); })
      .then(function(d) {
        if (d.outcome === 'success') {
          alert('Executed: ' + d.receipt.id + '\\nKilled: ' + d.receipt.summary.killed + ' process(es)');
        } else {
          alert('Error: ' + (d.reason || JSON.stringify(d)));
        }
        location.reload();
      })
      .catch(function(e) { alert('Network error: ' + e.message); });
    }

    /* Brittney — System Management chat (routes to /api/brittney/chat → operator loop) */
    function _bMsg(who, text, color) {
      var box = document.getElementById('brittney-messages'); if (!box) return null;
      var row = document.createElement('div');
      row.style.cssText = 'margin-bottom:10px;font-size:13px;line-height:1.5;font-family:system-ui,sans-serif';
      var label = document.createElement('span');
      label.style.cssText = 'color:' + color + ';font-weight:600'; label.textContent = who + ': ';
      var span = document.createElement('span');
      span.style.cssText = 'color:#c9d1d9;white-space:pre-wrap'; span.textContent = text;
      row.appendChild(label); row.appendChild(span);
      box.appendChild(row); box.scrollTop = box.scrollHeight; return row;
    }
    function sendBrittneyChat() {
      var inp = document.getElementById('brittney-input'); if (!inp) return;
      var msg = inp.value.trim(); if (!msg) return;
      inp.value = ''; _bMsg('You', msg, '#58a6ff');
      var pending = _bMsg('Brittney', 'thinking…', '#bc8cff');
      fetch('/api/brittney/chat', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ message: msg }) })
        .then(function(r) { return r.json(); })
        .then(function(d) {
          if (pending && pending.parentNode) pending.parentNode.removeChild(pending);
          if (d.error) { _bMsg('Brittney', 'error: ' + d.error, '#f85149'); return; }
          _bMsg('Brittney', d.reply, '#bc8cff');
          if (d.proposals && d.proposals.length) {
            var lines = d.proposals.map(function(x) { return '• ' + x.operation + (x.lane ? ' [' + x.lane + ']' : ''); }).join('\\n');
            _bMsg('Proposed actions', lines, '#3fb950');
          }
        })
        .catch(function(e) { if (pending && pending.parentNode) pending.parentNode.removeChild(pending); _bMsg('Brittney', 'network error: ' + e.message, '#f85149'); });
    }
    function initBrittneyChat() {
      var mount = document.getElementById('brittney-chat-mount'); if (!mount) return;
      mount.innerHTML =
        '<div id="brittney-messages" style="min-height:120px;max-height:300px;overflow-y:auto;padding:12px;background:#161b22;border-radius:8px;margin-bottom:10px"></div>' +
        '<div style="display:flex;gap:8px">' +
        '<input id="brittney-input" placeholder="Ask Brittney to manage the system…" style="flex:1;padding:10px 12px;border-radius:8px;border:1px solid #30363d;background:#0d1117;color:#c9d1d9;font-size:13px" />' +
        '<button id="brittney-send" style="padding:10px 18px;border-radius:8px;border:none;background:#238636;color:#fff;font-weight:600;cursor:pointer">Send</button>' +
        '</div>';
      document.getElementById('brittney-send').addEventListener('click', sendBrittneyChat);
      document.getElementById('brittney-input').addEventListener('keydown', function(e) { if (e.key === 'Enter') sendBrittneyChat(); });
      _bMsg('Brittney', 'Online. Ask me to manage the system — I propose permission-enveloped actions with receipts (Jetson-routed, $0).', '#bc8cff');
    }
    document.addEventListener('DOMContentLoaded', initBrittneyChat);
  </script>`;

html = html.replace('</body>', runtimeScript + '\n</body>');

mkdirSync(DIST_DIR, { recursive: true });
const outPath = join(DIST_DIR, 'operate-room.html');
writeFileSync(outPath, html, 'utf8');
console.log('Compiled:', outPath);
